import{_ as a,c as o,o as t,a1 as n}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Ganchos de Ciclo de Vida: Contexto Automatizado y Control de Calidad | oh-my-opencode","description":"Aprende el sistema de ganchos de ciclo de vida de oh-my-opencode. Domina las funcionalidades principales como inyección automática de AGENTS.md, cumplimiento forzoso de TODO, truncamiento de salida y detección de palabras clave.","frontmatter":{"title":"Ganchos de Ciclo de Vida: Contexto Automatizado y Control de Calidad | oh-my-opencode","sidebarTitle":"Haz los Agentes Más Inteligentes","subtitle":"Ganchos de Ciclo de Vida: Contexto Automatizado y Control de Calidad","description":"Aprende el sistema de ganchos de ciclo de vida de oh-my-opencode. Domina las funcionalidades principales como inyección automática de AGENTS.md, cumplimiento forzoso de TODO, truncamiento de salida y detección de palabras clave.","tags":["lifecycle-hooks","context-injection","quality-control"],"prerequisite":["start-sisyphus-orchestrator"],"order":120},"headers":[],"relativePath":"es/code-yeongyu/oh-my-opencode/advanced/lifecycle-hooks/index.md","filePath":"es/code-yeongyu/oh-my-opencode/advanced/lifecycle-hooks/index.md"}'),i={name:"es/code-yeongyu/oh-my-opencode/advanced/lifecycle-hooks/index.md"};function s(d,e,r,c,l,u){return t(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="ganchos-de-ciclo-de-vida-contexto-automatizado-y-control-de-calidad" tabindex="-1">Ganchos de Ciclo de Vida: Contexto Automatizado y Control de Calidad <a class="header-anchor" href="#ganchos-de-ciclo-de-vida-contexto-automatizado-y-control-de-calidad" aria-label="Permalink to &quot;Ganchos de Ciclo de Vida: Contexto Automatizado y Control de Calidad&quot;">​</a></h1><h2 id="lo-que-aprenderas-en-esta-leccion" tabindex="-1">Lo Que Aprenderás en Esta Lección <a class="header-anchor" href="#lo-que-aprenderas-en-esta-leccion" aria-label="Permalink to &quot;Lo Que Aprenderás en Esta Lección&quot;">​</a></h2><ul><li>Inyectar automáticamente contexto de proyecto a los agentes de IA (AGENTS.md, README.md)</li><li>Prevenir que los agentes dejen tareas a medio terminar, forzando la finalización de listas TODO</li><li>Truncar automáticamente salidas de herramientas demasiado grandes, evitando el desbordamiento de la ventana de contexto</li><li>Habilitar el modo Ultrawork para activar todos los agentes especializados con un solo clic</li><li>Personalizar configuraciones de ganchos para deshabilitar funciones que no necesitas</li></ul><h2 id="la-situacion-en-la-que-te-encuentras" tabindex="-1">La Situación en la que Te Encuentras <a class="header-anchor" href="#la-situacion-en-la-que-te-encuentras" aria-label="Permalink to &quot;La Situación en la que Te Encuentras&quot;">​</a></h2><p>¿Has experimentado alguno de estos problemas?</p><ul><li>¿Los agentes de IA siempre olvidan las especificaciones del proyecto y repiten errores?</li><li>¿El agente se detiene a mitad de camino sin terminar la lista TODO?</li><li>¿La búsqueda en la base de código produce salidas tan grandes que hacen estallar la ventana de contexto?</li><li>¿Tienes que decirle manualmente al agente qué modo de trabajo usar cada vez?</li></ul><h2 id="cuando-usar-esta-tecnica" tabindex="-1">Cuándo Usar Esta Técnica <a class="header-anchor" href="#cuando-usar-esta-tecnica" aria-label="Permalink to &quot;Cuándo Usar Esta Técnica&quot;">​</a></h2><p>Los ganchos de ciclo de vida son adecuados para los siguientes escenarios:</p><div class="tip custom-block"><p class="custom-block-title">Escenarios Típicos</p><ul><li><strong>Gestión de contexto de proyecto</strong>: Inyección automática de AGENTS.md y README.md</li><li><strong>Control de calidad</strong>: Verificación de comentarios de código, validación de bloques de pensamiento</li><li><strong>Continuidad de tareas</strong>: Forzar a los agentes a completar todas las tareas TODO</li><li><strong>Optimización de rendimiento</strong>: Truncamiento dinámico de salidas, gestión de ventana de contexto</li><li><strong>Automatización de flujos de trabajo</strong>: Palabras clave para activar modos, ejecución automática de comandos</li></ul></div><h2 id="la-idea-central" tabindex="-1">La Idea Central <a class="header-anchor" href="#la-idea-central" aria-label="Permalink to &quot;La Idea Central&quot;">​</a></h2><h3 id="¿que-son-los-ganchos-de-ciclo-de-vida" tabindex="-1">¿Qué Son los Ganchos de Ciclo de Vida? <a class="header-anchor" href="#¿que-son-los-ganchos-de-ciclo-de-vida" aria-label="Permalink to &quot;¿Qué Son los Ganchos de Ciclo de Vida?&quot;">​</a></h3><p><strong>Los ganchos de ciclo de vida</strong> son un mecanismo impulsado por eventos que te permite insertar lógica personalizada en puntos clave del trabajo del agente. Por ejemplo, inyectar automáticamente documentación de proyecto, forzar la finalización de tareas TODO, o truncar salidas excesivamente grandes. Estos ganchos escuchan 4 tipos de eventos: antes de ejecutar una herramienta, después de ejecutar una herramienta, cuando el usuario envía un mensaje, y cuando la sesión está inactiva. Al configurar ganchos razonablemente, puedes hacer que los agentes de IA sean más inteligentes y se ajusten mejor a tus hábitos de trabajo.</p><div class="info custom-block"><p class="custom-block-title">Ganchos vs Middleware</p><p>Los ganchos son muy similares al middleware de frameworks web, ambos son mecanismos de &quot;hacer cosas específicas en momentos específicos&quot;. La diferencia está en:</p><ul><li><strong>Middleware</strong>: Ejecución lineal, puede interrumpir la petición</li><li><strong>Ganchos</strong>: Impulsado por eventos, no puede interrumpir, solo puede modificar datos</li></ul></div><h3 id="_32-ganchos-7-categorias-principales" tabindex="-1">32 Ganchos, 7 Categorías Principales <a class="header-anchor" href="#_32-ganchos-7-categorias-principales" aria-label="Permalink to &quot;32 Ganchos, 7 Categorías Principales&quot;">​</a></h3><p>oh-my-opencode proporciona 32 ganchos integrados, divididos en 7 categorías principales:</p><table tabindex="0"><thead><tr><th>Categoría</th><th>Número de Ganchos</th><th>Función Principal</th></tr></thead><tbody><tr><td><strong>Inyección de Contexto</strong></td><td>4</td><td>Inyección automática de documentación de proyecto, reglas</td></tr><tr><td><strong>Productividad y Control</strong></td><td>6</td><td>Detección de palabras clave, cambio de modo, gestión de bucles</td></tr><tr><td><strong>Calidad y Seguridad</strong></td><td>4</td><td>Verificación de comentarios de código, validación de bloques de pensamiento</td></tr><tr><td><strong>Recuperación y Estabilidad</strong></td><td>3</td><td>Recuperación de sesión, manejo de errores</td></tr><tr><td><strong>Truncamiento y Gestión de Contexto</strong></td><td>2</td><td>Truncamiento de salida, monitoreo de ventana</td></tr><tr><td><strong>Notificaciones y UX</strong></td><td>3</td><td>Actualizaciones de versión, notificaciones de tareas en segundo plano, recordatorios de inactividad</td></tr><tr><td><strong>Gestión de Tareas</strong></td><td>2</td><td>Recuperación de tareas, reintento de delegación</td></tr></tbody></table><h2 id="tipos-de-eventos-de-ganchos" tabindex="-1">Tipos de Eventos de Ganchos <a class="header-anchor" href="#tipos-de-eventos-de-ganchos" aria-label="Permalink to &quot;Tipos de Eventos de Ganchos&quot;">​</a></h2><p>Los ganchos escuchan los siguientes 4 tipos de eventos:</p><h3 id="_1-pretooluse-antes-de-ejecutar-herramienta" tabindex="-1">1. PreToolUse (Antes de Ejecutar Herramienta) <a class="header-anchor" href="#_1-pretooluse-antes-de-ejecutar-herramienta" aria-label="Permalink to &quot;1. PreToolUse (Antes de Ejecutar Herramienta)&quot;">​</a></h3><p><strong>Momento de Activación</strong>: Antes de que el agente llame a una herramienta</p><p><strong>Qué Puede Hacer</strong>:</p><ul><li>Prevenir la ejecución de la herramienta</li><li>Modificar parámetros de la herramienta</li><li>Inyectar contexto</li></ul><p><strong>Ganchos de Ejemplo</strong>: <code>comment-checker</code>, <code>directory-agents-injector</code></p><h3 id="_2-posttooluse-despues-de-ejecutar-herramienta" tabindex="-1">2. PostToolUse (Después de Ejecutar Herramienta) <a class="header-anchor" href="#_2-posttooluse-despues-de-ejecutar-herramienta" aria-label="Permalink to &quot;2. PostToolUse (Después de Ejecutar Herramienta)&quot;">​</a></h3><p><strong>Momento de Activación</strong>: Después de que la herramienta se ejecuta</p><p><strong>Qué Puede Hacer</strong>:</p><ul><li>Modificar la salida de la herramienta</li><li>Agregar mensajes de advertencia</li><li>Inyectar instrucciones posteriores</li></ul><p><strong>Ganchos de Ejemplo</strong>: <code>tool-output-truncator</code>, <code>directory-readme-injector</code></p><h3 id="_3-userpromptsubmit-cuando-el-usuario-envia-mensaje" tabindex="-1">3. UserPromptSubmit (Cuando el Usuario Envía Mensaje) <a class="header-anchor" href="#_3-userpromptsubmit-cuando-el-usuario-envia-mensaje" aria-label="Permalink to &quot;3. UserPromptSubmit (Cuando el Usuario Envía Mensaje)&quot;">​</a></h3><p><strong>Momento de Activación</strong>: Cuando el usuario envía un mensaje a la sesión</p><p><strong>Qué Puede Hacer</strong>:</p><ul><li>Prevenir el envío (raro)</li><li>Modificar el contenido del mensaje</li><li>Inyectar mensajes del sistema</li><li>Activar modos de trabajo</li></ul><p><strong>Ganchos de Ejemplo</strong>: <code>keyword-detector</code>, <code>auto-slash-command</code></p><h3 id="_4-stop-cuando-la-sesion-esta-inactiva" tabindex="-1">4. Stop (Cuando la Sesión Está Inactiva) <a class="header-anchor" href="#_4-stop-cuando-la-sesion-esta-inactiva" aria-label="Permalink to &quot;4. Stop (Cuando la Sesión Está Inactiva)&quot;">​</a></h3><p><strong>Momento de Activación</strong>: Cuando el agente deja de trabajar y la sesión entra en estado inactivo</p><p><strong>Qué Puede Hacer</strong>:</p><ul><li>Inyectar mensajes posteriores</li><li>Enviar notificaciones</li><li>Verificar el estado de las tareas</li></ul><p><strong>Ganchos de Ejemplo</strong>: <code>todo-continuation-enforcer</code>, <code>session-notification</code></p>',38)])])}const h=a(i,[["render",s]]);export{p as __pageData,h as default};
